det_check_template:
proof fn det_init<T: Copy, const N: usize>(pre_self_: StaticLinkedList<T, N>, post1_self_: StaticLinkedList<T, N>, r1: (), post2_self_: StaticLinkedList<T, N>, r2: ())
    requires (N > 2), (N < SLLIndex::MAX), (pre_self_.array_wf()),
    ensures
        ({
            &&& (post1_self_.wf())
            &&& (post1_self_@ =~= Seq::empty())
            &&& (post1_self_.len() == 0)
            &&& (post2_self_.wf())
            &&& (post2_self_@ =~= Seq::empty())
            &&& (post2_self_.len() == 0)
        }) ==> det_init_equal(r1, r2, post1_self_, post2_self_),
{
{ASSUMES}}

equal_fn_def:
// Generated equal-fn for determinism check.
// Policy: errs_equivalent=True, opaque_ok=False
spec fn det_init_equal<T: Copy, const N: usize>(r1: (), r2: (), post1_self_: StaticLinkedList<T, N>, post2_self_: StaticLinkedList<T, N>) -> bool {
    (r1 == r2)
    && (post1_self_ == post2_self_)
}
